-- =============================================================================
-- Medical Center CMS — FULL DATABASE SETUP (single run)
-- HeidiSQL: File → Run SQL file… → select this file only
-- Includes: schema, seed users, clinical state, indexes, PhilHealth case rates
-- Generated from 01–06 scripts. Safe to re-run (IF NOT EXISTS / ON DUPLICATE KEY).
-- =============================================================================


-- #############################################################################
-- FILE: 01_schema.sql
-- #############################################################################

-- =============================================================================
-- Medical Center CMS — MariaDB schema
-- Run this script in HeidiSQL (File → Run SQL file, or paste into Query tab)
-- =============================================================================

CREATE DATABASE IF NOT EXISTS `medical_center`
  CHARACTER SET utf8mb4
  COLLATE utf8mb4_unicode_ci;

USE `medical_center`;

-- -----------------------------------------------------------------------------
-- Users (authentication & access control)
-- -----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS `users` (
  `id`            CHAR(36)     NOT NULL,
  `username`      VARCHAR(100) NOT NULL,
  `password_hash` VARCHAR(255) NOT NULL,
  `full_name`     VARCHAR(255) NOT NULL,
  `role`          ENUM('Administrator', 'Doctor', 'Receptionist', 'Cashier') NOT NULL,
  `active`        TINYINT(1)   NOT NULL DEFAULT 1,
  `dark_mode`     TINYINT(1)   NOT NULL DEFAULT 0,
  `page_access`   JSON         NULL,
  `created_at`    TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at`    TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_users_username` (`username`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- -----------------------------------------------------------------------------
-- Hospital profile (single-row settings)
-- -----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS `hospital_settings` (
  `id`                       CHAR(36)     NOT NULL DEFAULT 'default',
  `name`                     VARCHAR(255) NOT NULL,
  `address`                  TEXT         NOT NULL,
  `phone`                    VARCHAR(50)  NOT NULL,
  `email`                    VARCHAR(255) NOT NULL,
  `philhealth_accreditation` VARCHAR(100) NOT NULL,
  `tin`                      VARCHAR(50)  NOT NULL,
  `updated_at`               TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- -----------------------------------------------------------------------------
-- Patients
-- -----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS `patients` (
  `id`              CHAR(36)     NOT NULL,
  `first_name`      VARCHAR(100) NOT NULL,
  `middle_name`     VARCHAR(100) NULL,
  `last_name`       VARCHAR(100) NOT NULL,
  `suffix`          VARCHAR(20)  NULL,
  `birth_date`      DATE         NOT NULL,
  `gender`          ENUM('Male', 'Female') NOT NULL,
  `civil_status`    ENUM('Single', 'Married', 'Widowed', 'Separated') NOT NULL,
  `contact_number`  VARCHAR(50)  NOT NULL,
  `email`           VARCHAR(255) NULL,
  `street`          VARCHAR(255) NOT NULL,
  `barangay`        VARCHAR(100) NOT NULL,
  `city`            VARCHAR(100) NOT NULL,
  `province`        VARCHAR(100) NOT NULL,
  `zip`             VARCHAR(20)  NULL,
  `emergency_name`  VARCHAR(255) NOT NULL,
  `emergency_phone` VARCHAR(50)  NOT NULL,
  `emergency_rel`   VARCHAR(100) NULL,
  `philhealth_no`   VARCHAR(50)  NULL,
  `extended_data`   JSON         NULL,
  `archived`        TINYINT(1)   NOT NULL DEFAULT 0,
  `created_at`      TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at`      TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_patients_name` (`last_name`, `first_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- -----------------------------------------------------------------------------
-- Auth sessions (optional server-side session tracking)
-- -----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS `auth_sessions` (
  `id`         CHAR(36)     NOT NULL,
  `user_id`    CHAR(36)     NOT NULL,
  `token`      VARCHAR(255) NOT NULL,
  `expires_at` TIMESTAMP    NOT NULL,
  `created_at` TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_auth_sessions_token` (`token`),
  KEY `idx_auth_sessions_user` (`user_id`),
  CONSTRAINT `fk_auth_sessions_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- -----------------------------------------------------------------------------
-- PhilHealth case rates (Case Rate Type catalog from previous clinic_management)
-- -----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS `philhealth_records` (
  `id`                      INT(11)       NOT NULL AUTO_INCREMENT,
  `case_code`               VARCHAR(20)   NOT NULL,
  `case_description`        TEXT          NOT NULL,
  `case_type`               VARCHAR(20)   NOT NULL,
  `case_rate`               DECIMAL(12,2) NOT NULL,
  `health_facility_fee`     DECIMAL(12,2) NOT NULL DEFAULT 0,
  `professional_fee_amount` DECIMAL(12,2) NOT NULL DEFAULT 0,
  `price_effective_date`    DATE          NULL,
  `hospital_share_pct`      DECIMAL(5,2)  NOT NULL DEFAULT 70.00,
  `professional_fee_pct`    DECIMAL(5,2)  NOT NULL DEFAULT 30.00,
  `is_active`               TINYINT(1)    NOT NULL DEFAULT 1,
  `created_at`              DATETIME      NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at`              DATETIME      NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_philhealth_case_code` (`case_code`),
  KEY `idx_philhealth_case_type` (`case_type`),
  KEY `idx_philhealth_active` (`is_active`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


