-- Demo clinical data (patients, bills, admissions, etc.) is seeded by npm run db:seed
-- into app_clinical_state + patients (see scripts/demo-clinical-seed.mjs).
-- Official PhilHealth case rates are seeded by 06_philhealth_case_rates_seed.sql.


-- #############################################################################
-- FILE: 03_clinical_data.sql
-- #############################################################################

-- =============================================================================
-- Clinical registry persistence (all module data as JSON + normalized patients)
-- Run AFTER 01_schema.sql and 02_seed.sql
-- =============================================================================

USE `medical_center`;

-- Full app clinical payload (patients, appointments, consultations, billing, etc.)
CREATE TABLE IF NOT EXISTS `app_clinical_state` (
  `id`         CHAR(36)   NOT NULL DEFAULT 'default',
  `payload`    LONGTEXT   NOT NULL,
  `updated_at` TIMESTAMP  NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Extra patient fields (ignore error if column already exists when run manually)
-- ALTER TABLE `patients` ADD COLUMN `extended_data` JSON NULL AFTER `philhealth_no`;


-- #############################################################################
-- FILE: 04_indexes.sql
-- #############################################################################

-- =============================================================================
-- Performance indexes for frequently queried columns
-- Run AFTER 01_schema.sql (safe to re-run — skips existing indexes)
-- =============================================================================

USE `medical_center`;

-- Patients: filter by archived status, registration date, PhilHealth lookup
CREATE INDEX IF NOT EXISTS `idx_patients_archived` ON `patients` (`archived`);
CREATE INDEX IF NOT EXISTS `idx_patients_created_at` ON `patients` (`created_at`);
CREATE INDEX IF NOT EXISTS `idx_patients_philhealth_no` ON `patients` (`philhealth_no`);

-- Auth sessions: expiry cleanup and token validation
CREATE INDEX IF NOT EXISTS `idx_auth_sessions_expires` ON `auth_sessions` (`expires_at`);


-- #############################################################################
-- FILE: 05_philhealth_records.sql
-- #############################################################################

-- =============================================================================
-- PhilHealth Case Rates (Case Rate Type) — upgrade from clinic_management
-- Run AFTER 01_schema.sql
--
-- To import your previous catalog (~9k rows):
--   npm run db:import-case-rates
-- =============================================================================

USE `medical_center`;

CREATE TABLE IF NOT EXISTS `philhealth_records` (
  `id`                      INT(11)       NOT NULL AUTO_INCREMENT,
  `case_code`               VARCHAR(20)   NOT NULL,
  `case_description`        TEXT          NOT NULL,
  `case_type`               VARCHAR(20)   NOT NULL,
  `case_rate`               DECIMAL(12,2) NOT NULL,
  `health_facility_fee`     DECIMAL(12,2) NOT NULL DEFAULT 0,
  `professional_fee_amount` DECIMAL(12,2) NOT NULL DEFAULT 0,
  `price_effective_date`    DATE          NULL,
  `hospital_share_pct`      DECIMAL(5,2)  NOT NULL DEFAULT 70.00,
  `professional_fee_pct`    DECIMAL(5,2)  NOT NULL DEFAULT 30.00,
  `is_active`               TINYINT(1)    NOT NULL DEFAULT 1,
  `created_at`              DATETIME      NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at`              DATETIME      NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_philhealth_case_code` (`case_code`),
  KEY `idx_philhealth_case_type` (`case_type`),
  KEY `idx_philhealth_active` (`is_active`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


